        db.on('load', function() {
            let testData = {name: 'John', age: 30};
            db.set('user1', testData);

            let result = db.get('user1');
            assert.deepStrictEqual(result, testData);
            done();
        });
    });

    it('should return updated value after modification', function(done) {
        db.on('load', function() {
            let originalData = {name: 'Alice', age: 25};
            let updatedData = {name: 'Alice', age: 26};

            db.set('user2', originalData);
            let firstResult = db.get('user2');
            assert.deepStrictEqual(firstResult, originalData);

            db.set('user2', updatedData);
            let secondResult = db.get('user2');
            assert.deepStrictEqual(secondResult, updatedData);
            done();
        });
    });

    it('should handle different data types', function(done) {
        db.on('load', function() {
            // Test string
            db.set('string_key', 'hello world');
            assert.strictEqual(db.get('string_key'), 'hello world');

