            db.set('number_key', 42);
            assert.strictEqual(db.get('number_key'), 42);

            // Test boolean
            db.set('boolean_key', true);
            assert.strictEqual(db.get('boolean_key'), true);

            // Test array
            let testArray = [1, 2, 3, 'test'];
            db.set('array_key', testArray);
            assert.deepStrictEqual(db.get('array_key'), testArray);

            // Test null
            db.set('null_key', null);
            assert.strictEqual(db.get('null_key'), null);

            done();
        });
    });

    it('should return undefined after key is removed', function(done) {
        db.on('load', function() {
            db.set('temp_key', {data: 'temporary'});
            assert.notStrictEqual(db.get('temp_key'), undefined);

            db.rm('temp_key');
            assert.strictEqual(db.get('temp_key'), undefined);
            done();
        });
    });
});
